#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void kmeans_assign_clusters(
    __global const float* attributes,
    __global const float* clusters,
    __global int* membership,
    __global float* partial_new_centers,
    __global int* partial_new_centers_len,
    const int npoints,
    const int nfeatures,
    const int nclusters)
{
    int gid = get_global_id(0);
    if (gid >= npoints) return;

    // Find nearest cluster
    int nearest_index = 0;
    float min_dist = FLT_MAX;
    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        for (int f = 0; f < nfeatures; f++) {
            float diff = attributes[gid * nfeatures + f] - clusters[c * nfeatures + f];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            nearest_index = c;
        }
    }

    // Update membership and partial sums atomically
    int old_membership = membership[gid];
    membership[gid] = nearest_index;

    // Atomically increment partial_new_centers_len for this cluster
    atomic_inc(&partial_new_centers_len[nearest_index]);

    // Atomically add feature values to partial_new_centers for this cluster
    for (int f = 0; f < nfeatures; f++) {
        atomic_add(&partial_new_centers[nearest_index * nfeatures + f], attributes[gid * nfeatures + f]);
    }
}

__kernel void kmeans_update_clusters(
    __global float* clusters,
    __global float* new_centers,
    __global int* new_centers_len,
    const int nfeatures,
    const int nclusters)
{
    int cid = get_global_id(0);
    if (cid >= nclusters) return;

    int len = new_centers_len[cid];
    if (len > 0) {
        for (int f = 0; f < nfeatures; f++) {
            clusters[cid * nfeatures + f] = new_centers[cid * nfeatures + f] / (float)len;
        }
    }
    // Reset new_centers and new_centers_len for next iteration
    for (int f = 0; f < nfeatures; f++) {
        new_centers[cid * nfeatures + f] = 0.0f;
    }
    new_centers_len[cid] = 0;
}
